import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Router } from '@angular/router';
import { AlumnoDashboardService, AlumnoCurso } from '../../../core/services/alumno-dashboard.service';

@Component({
  selector: 'app-mis-cursos',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './mis-cursos.component.html',
  styleUrls: ['./mis-cursos.component.css']
})
export class MisCursosComponent implements OnInit {
  private studentService = inject(AlumnoDashboardService);
  private router = inject(Router);

  cursos: AlumnoCurso[] = [];
  isLoading = true;

  ngOnInit(): void {
    this.studentService.getEnrolledCursos().subscribe({
      next: (data) => {
        this.cursos = data;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error fetching enrolled courses:', err);
        this.isLoading = false;
      }
    });
  }

  continueCourse(courseId: number): void {
    this.router.navigate(['/dashboard/cursos-play', courseId]);
  }
}
<div class="space-y-8 font-body text-slate-800 dark:text-slate-200 transition-colors duration-300">

  <!-- Banner Header -->
  <div class="border border-slate-200 dark:border-slate-800 p-8 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] transition-colors duration-300">
    <h1 class="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight uppercase leading-none">Mis Cursos</h1>
    <p class="text-slate-500 dark:text-slate-400 text-xs mt-2">Explora las asignaturas y talleres en los que estás inscrito. Revisa tu progreso académico.</p>
  </div>

  <!-- Loading State -->
  <div *ngIf="isLoading" class="flex flex-col items-center justify-center p-20 border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 transition-colors duration-300">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-primary border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Cargando tus cursos...</span>
  </div>

  <!-- No courses state -->
  <div *ngIf="!isLoading && cursos.length === 0" class="border border-slate-200 dark:border-slate-800 p-12 text-center bg-white dark:bg-slate-900 transition-colors duration-300">
    <span class="material-symbols-outlined text-5xl text-slate-300 dark:text-slate-600 mb-2">auto_stories</span>
    <h3 class="text-sm font-bold text-slate-800 dark:text-slate-100 uppercase">Aún no estás matriculado</h3>
    <p class="text-slate-500 dark:text-slate-400 text-xs mt-1.5 max-w-sm mx-auto">No tienes cursos activos en tu suscripción. Contacta al soporte técnico o solicita la aprobación de un pago.</p>
  </div>

  <!-- Courses Grid -->
  <div *ngIf="!isLoading && cursos.length > 0" class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
    <div 
      *ngFor="let curso of cursos"
      class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex flex-col justify-between rounded-none hover:shadow-[6px_6px_0px_0px_rgba(15,23,42,0.08)] dark:hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,0.28)] transition-all overflow-hidden duration-300">

      <!-- Top header portadas -->
      <div>
        <div class="relative h-44 bg-slate-100 dark:bg-slate-800 border-b border-slate-200 dark:border-slate-800 overflow-hidden">
          <img 
            [src]="curso.imagenPortada || 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3'" 
            class="w-full h-full object-cover transition-transform duration-500 hover:scale-105" 
            alt="Portada Curso">
          <span 
            [ngClass]="{
              'bg-emerald-50 text-emerald-700 border-emerald-200': curso.nivelSuscripcion === 'BASICO',
              'bg-blue-50 text-blue-700 border-blue-200': curso.nivelSuscripcion === 'INTERMEDIO',
              'bg-amber-50 text-amber-700 border-amber-200': curso.nivelSuscripcion === 'PREMIUM'
            }" 
            class="absolute top-3 right-3 text-[9px] font-black uppercase tracking-widest border px-2 py-0.5 rounded-none shadow-[2px_2px_0px_0px_rgba(15,23,42,0.1)]">
            {{ curso.nivelSuscripcion }}
          </span>
        </div>

        <!-- Body context -->
        <div class="p-6">
          <h2 class="text-sm font-black text-slate-900 dark:text-slate-100 uppercase tracking-tight leading-snug line-clamp-1">
            {{ curso.nombre }}
          </h2>
          <p class="text-slate-500 dark:text-slate-400 text-xs mt-2 line-clamp-3 leading-relaxed">
            {{ curso.descripcion }}
          </p>
        </div>
      </div>

      <!-- Footer progress and actions -->
      <div class="p-6 pt-0 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
        <!-- Progress metadata -->
        <div class="mt-4">
          <div class="flex justify-between items-center text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1.5">
            <span>Progreso</span>
            <span class="font-mono text-slate-900 dark:text-slate-100">{{ curso.avancePorcentaje }}%</span>
          </div>
          <!-- Progress bar -->
          <div class="w-full bg-slate-200 dark:bg-slate-800 h-2 border border-slate-300 dark:border-slate-700 rounded-none overflow-hidden">
            <div 
              class="bg-slate-900 dark:bg-slate-100 h-full transition-all duration-500" 
              [style.width.%]="curso.avancePorcentaje">
            </div>
          </div>
        </div>

        <!-- Buttons play -->
        <div class="mt-6">
          <button 
            (click)="continueCourse(curso.id)" 
            class="w-full py-2.5 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-widest hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none border border-slate-900 dark:border-slate-100 flex items-center justify-center gap-2">
            <span class="material-symbols-outlined text-sm">play_circle</span>
            <span>{{ curso.avancePorcentaje > 0 ? 'Continuar Aprendizaje' : 'Iniciar Curso' }}</span>
          </button>
        </div>
      </div>

    </div>
  </div>

</div>
